mapper.select:
SELECT r.*, u.username AS reporterName, CASE WHEN r.target_type = 'POST' THEN p.title WHEN r.target_type = 'COMMENT' THEN c.content ELSE NULL END AS targetTitle FROM biz_report r LEFT JOIN sys_user u ON r.reporter_id = u.user_id LEFT JOIN biz_post p ON r.target_type = 'POST' AND r.target_id = p.id LEFT JOIN biz_comment c ON r.target_type = 'COMMENT' AND r.target_id = c.id
AND r.target_type = #{targetType}
AND r.status = #{status}
AND r.resolve_action = #{resolveAction}
ORDER BY r.create_time DESC
